final:
module top_module (
    input [1:0] a,
    output reg not_b
);

    always @(*) begin
        case (a)
            2'b00: not_b = 0;
            2'b01: not_b = 1;
            2'b10: not_b = 1;
            2'b11: not_b = 0;
            default: not_b = 0; // Default case
        endcase
    end
endmodule
